{"code": "from hermes_tools import terminal
import time, json

time.sleep(10)

# Test all models
models = ["claude-sonnet-4", "deepseek-chat", "groq-llama", "groq-qwen", "groq-deepseek"]
results = {}
for model in models:
    result = terminal(
        f'curl -s http://localhost:4000/v1/chat/completions '
        f'-H "Content-Type: application/json" '
        f'-H "Authorization: Bearer sk-hermes-litellm-sunstein-2026" '
        f'-d \'{{"model":"{model}","messages":[{{"role":"user","content":"say hello in 3 words"}}]}}\'',
        timeout=30
    )
    try:
        resp = json.loads(result['output'])
        if 'error' in resp:
            msg = resp['error']['message'][:100]
            results[model] = f"ERROR: {msg}"
        else:
            results[model] = resp['choices'][0]['message']['content']
    except:
        results[model] = f"PARSE ERROR: {result['output'][:100]}"
    print(f"{model}: {results[model]}")

print("\n=== Summary ===")
for m, r in results.items():
    status = "✅" if "ERROR" not in r else "❌"
    print(f"  {status} {m}: {r[:60]}")
"}

